template.t:

                }

                /* ── Botones ─────────────────────────────────────── */
                .dg-btn {
                    display: inline-flex; align-items: center; gap: .4rem;
                    padding: .55rem 1.1rem; border-radius: 8px;
                    font-weight: 600; font-size: .875rem;
                    cursor: pointer; border: none; transition: all .15s;
                    text-decoration: none;
                }
                .dg-btn--primary { background: var(--dg-primary); color: #fff; }
                .dg-btn--primary:hover { background: var(--color-700); color: var(--color-white); transform: translateY(-1px); }
                .dg-btn--outline {
                    background: transparent; color: var(--dg-primary);
                    border: 1.5px solid var(--dg-primary);
                }
                .dg-btn--outline:hover { background: var(--dg-primary-light); color: var(--dg-primary); }
                .dg-btn--ghost {
                    background: var(--dg-bg); color: var(--dg-muted);
                    border: 1px solid var(--dg-border);
                }

                /* ── Card de miembro ─────────────────────────────── */
                .dg-member-card {
                    background: var(--dg-surface);
                    border: 1px solid var(--dg-border);
                    border-radius: var(--dg-radius);
                    padding: 1rem 1.25rem;
                    display: flex; align-items: center; gap: 1rem;
                    box-shadow: var(--dg-shadow);
                    transition: box-shadow .15s;
                }
                .dg-member-card:hover { box-shadow: var(--dg-shadow-md); }
                .dg-member-card.inactive { opacity: .6; }

                /* Avatar */
                .dg-avatar {
                    width: 42px; height: 42px; border-radius: 50%;
                    background: var(--dg-primary-light);
                    color: var(--dg-primary);
                    display: flex; align-items: center; justify-content: center;
                    font-weight: 800; font-size: 1rem; flex-shrink: 0;
                    text-transform: uppercase;
                }
                .dg-avatar--lider {
                    background: linear-gradient(135deg, #fef3c7, #fde68a);
                    color: #92400e;
                    border: 2px solid #f59e0b;
                }

                .dg-member-name { font-weight: 700; font-size: .925rem; color: var(--dg-text); }
                .dg-member-meta { font-size: .78rem; color: var(--dg-muted); margin-top: .1rem; }

                /* Badges */
                .dg-badge {
                    display: inline-flex; align-items: center; gap: .3rem;
                    padding: .2rem .65rem; border-radius: 99px;
                    font-size: .72rem; font-weight: 600;
                }
                .dg-badge--active  { background: #d1fae5; color: var(--dg-success); }
                .dg-badge--inactive{ background: var(--color-50); color: var(--dg-danger); }
                .dg-badge--lider   { background: #fef3c7; color: #92400e; }

                /* ── Alertas ─────────────────────────────────────── */
                .dg-alert {
                    border-radius: 10px; padding: .8rem 1rem;
                    font-size: .875rem; display: flex; align-items: center; gap: .6rem;
                }
                .dg-alert--success { background: #d1fae5; color: #065f46; }
                .dg-alert--danger  { background: var(--color-50); color: var(--color-800); }
                .dg-alert--info    { background: #dbeafe; color: #1e40af; }

                /* ── Vacío ───────────────────────────────────────── */
                .dg-empty {
                    text-align: center; padding: 3.5rem 1rem; color: var(--dg-muted);
                }
                .dg-empty i { font-size: 2.5rem; opacity: .3; display: block; margin-bottom: .75rem; }
                .dg-empty p { font-size: .875rem; margin: 0; }

                /* ── Modal personalizado ─────────────────────────── */
                .dg-modal .modal-content {
                    border-radius: var(--dg-radius);
                    border: none;
                    box-shadow: 0 20px 60px rgba(0,0,0,.15);
                }
                .dg-modal .modal-header {
                    border-bottom: 1px solid var(--dg-border);
                    padding: 1.25rem 1.5rem;
                }
                .dg-modal .modal-title {
                    font-weight: 800; font-size: 1.05rem; color: var(--dg-text);
                }
                .dg-modal .modal-body { padding: 1.5rem; }
                .dg-modal .modal-footer {
                    border-top: 1px solid var(--dg-border);
                    padding: 1rem 1.5rem;
                }

                /* Input de búsqueda del modal */
                .dg-search-input {
                    width: 100%;
                    border: 1.5px solid var(--dg-border);
                    border-radius: 10px;
                    padding: .6rem 1rem .6rem 2.5rem;
                    font-size: .9rem; color: var(--dg-text);
                    outline: none; transition: border-color .15s;
                    background: var(--dg-bg);
                }
                .dg-search-input:focus { border-color: var(--dg-primary); background: #fff; }
                .dg-search-wrap { position: relative; }
                .dg-search-wrap i {
                    position: absolute; left: .85rem; top: 50%;
                    transform: translateY(-50%); color: var(--dg-muted);
                    pointer-events: none;
                }

                /* Resultados de búsqueda */
                .dg-search-results { margin-top: .5rem; }
                .dg-result-item {
                    display: flex; align-items: center; gap: .75rem;
                    padding: .65rem .9rem; border-radius: 8px;
                    cursor: pointer; transition: background .1s;
                    border: none; width: 100%; text-align: left;
                    background: transparent; color: var(--dg-text);
                    font-size: .875rem;
                }
                .dg-result-item:hover { background: var(--dg-primary-light); color: var(--dg-primary); }
                .dg-result-item.selected {
                    background: var(--dg-primary-light);
                    color: var(--dg-primary); font-weight: 600;
                }
                .dg-result-item i { color: var(--dg-muted); font-size: .85rem; }
                .dg-result-new {
                    padding: .6rem .9rem; border-radius: 8px;
                    background: #fef3c7; color: #92400e;
                    font-size: .82rem; display: flex; align-items: center; gap: .5rem;
                }

                /* ── Volver ──────────────────────────────────────── */
                .dg-back {
                    display: inline-flex; align-items: center; gap: .4rem;
                    color: var(--dg-muted); font-size: .82rem;
                    text-decoration: none; margin-bottom: 1.25rem;
                    transition: color .15s;
                }
                .dg-back:hover { color: var(--dg-primary); }






