                (function() {
                'use strict';

                var proyectoId = <t t-esc="proyecto.id" />;
                var csrfToken  = '';

                var inputBuscar   = document.getElementById('inputBuscarMiembro');
                var divResultados = document.getElementById('resultadosMiembros');
                var btnConfirmar  = document.getElementById('btnConfirmarMiembro');
                var divNuevo      = document.getElementById('divNuevoMiembro');
                var msgExito      = document.getElementById('msg-miembro-exito');
                var msgError      = document.getElementById('msg-miembro-error');

                var partnerId   = null;
                var nombreNuevo = null;
                var debounceTimer;

                inputBuscar.addEventListener('input', function() {
                    clearTimeout(debounceTimer);
                    var term = this.value.trim();
                    partnerId = null; nombreNuevo = null;
                    btnConfirmar.disabled = true;
                    divResultados.innerHTML = '';
                    divNuevo.classList.add('d-none');

                    if (term.length < 2) return;

                    debounceTimer = setTimeout(function() {
                        fetch('/digitalizacion/api/v1/partners/search', {
                            method: 'POST',
                            headers: { 
                                'Content-Type': 'application/json',
                                'X-CSRF-Token': csrfToken
                            },
                            body: JSON.stringify({
                                jsonrpc: '2.0', method: 'call', id: 1,
                                params: { term: term, proyecto_id: proyectoId }
                            })
                        })
                        .then(function(r) { return r.json(); })
                        .then(function(response) {
                            var data = response.result || {};
                            var partners = data.data || [];
                            divResultados.innerHTML = '';

                            if (partners.length === 0) {
                                nombreNuevo = term;
                                divNuevo.classList.remove('d-none');
                                btnConfirmar.disabled = false;
                            } else {
                                partners.forEach(function(p) {
                                    var btn = document.createElement('button');
                                    btn.className = 'o_digitalizacion_result-item';
                                    var label = p.name;
                                    if (p.email) label += ' (' + p.email + ')';
                                    btn.textContent = label;
                                    btn.addEventListener('click', function() {
                                        partnerId = p.id; nombreNuevo = null;
                                        inputBuscar.value = p.name;
                                        divResultados.innerHTML = '';
                                        divNuevo.classList.add('d-none');
                                        btnConfirmar.disabled = false;
                                        btn.classList.add('selected');
                                    });
                                    divResultados.appendChild(btn);
                                });
                            }
                        })
                        .catch(function() {
                            divResultados.textContent = 'Error al buscar contactos.';
                        });
                    }, 350);
                });

                btnConfirmar.addEventListener('click', function() {
                    btnConfirmar.disabled = true;
                    fetch('/digitalizacion/api/v1/proyectos/' + proyectoId + '/miembros', {
                        method: 'POST',
                        headers: { 
                            'Content-Type': 'application/json',
                            'X-CSRF-Token': csrfToken
                        },
                        body: JSON.stringify({
                            jsonrpc: '2.0', method: 'call', id: 1,
                            params: {
                                proyecto_id: proyectoId,
                                partner_id:  partnerId   || null,
                                nombre_nuevo: nombreNuevo || null
                            }
                        })
                    })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        var result = data.result || {};
                        try {
                            if (window.bootstrap) {
                                var modal = window.bootstrap.Modal.getInstance(document.getElementById('modalAgregarMiembro'));
                                if (modal) modal.hide();
                            } else {
                                document.getElementById('modalAgregarMiembro').classList.remove('show');
                                document.getElementById('modalAgregarMiembro').style.display = 'none';
                                document.body.classList.remove('modal-open');
                                var backdrop = document.querySelector('.modal-backdrop');
                                if (backdrop) backdrop.remove();
                            }
                        } catch(e) { console.warn(e); }
                        if (result.success) {
                            msgExito.classList.remove('d-none');
                            msgError.classList.add('d-none');
                            setTimeout(function() { location.reload(); }, 800);
                        } else {
                            var errMsg = result.error ? (result.error.message ? result.error.message : 'Error al agregar miembro.') : 'Error al agregar miembro.';
                            msgError.textContent = errMsg;
                            msgError.classList.remove('d-none');
                            msgExito.classList.add('d-none');
                            btnConfirmar.disabled = false;
                        }
                    })
                    .catch(function(err) {
                        msgError.textContent = 'Error de conexión / JS: ' + (err ? err.message : 'Desconocido');
                        msgError.classList.remove('d-none');
                        btnConfirmar.disabled = false;
                    });
                });

                document.getElementById('modalAgregarMiembro')
                    .addEventListener('hidden.bs.modal', function() {
                        inputBuscar.value = '';
                        divResultados.innerHTML = '';
                        divNuevo.classList.add('d-none');
                        btnConfirmar.disabled = true;
                        partnerId = null; nombreNuevo = null;
                    });
                })();
